import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import Navbar from "../../components/Navbar";
import "../../styles/landing.css";

const LandingPage = () => {
  const navigate = useNavigate();
  const { isAuthenticated, user } = useAuth();

  // ✅ Already logged in → role பாத்து dashboard redirect
  useEffect(() => {
    if (isAuthenticated && user?.role) {
      if (user.role === "admin") navigate("/admin/dashboard", { replace: true });
      else if (user.role === "client") navigate("/client/dashboard", { replace: true });
      else navigate("/freelancer/dashboard", { replace: true });
    }
  }, [isAuthenticated, user, navigate]);

  // Logged in இருந்தா redirect ஆகும் — nothing render பண்ணாத
  if (isAuthenticated) return null;

  return (
    <div className="landing">
      <Navbar />

      {/* HERO */}
      <section className="hero">
        <h1>
          Find Top <span>Freelancers</span><br />
          for Your Projects
        </h1>
        <p>
          Connect with skilled freelancers and clients. Post projects,
          send proposals, and get work done — all in one place.
        </p>
        <div className="hero-buttons">
          <button className="btn-primary" onClick={() => navigate("/register")}>
            Get Started
          </button>
          <button className="btn-secondary" onClick={() => navigate("/login")}>
            Login
          </button>
        </div>
      </section>

      {/* FEATURES */}
      <section className="features">
        <h2>Why FreelanceHub?</h2>
        <div className="feature-cards">
          <div className="feature-card">
            <div className="icon">🚀</div>
            <h3>Post Projects Fast</h3>
            <p>Clients can post projects in minutes and receive proposals from top freelancers.</p>
          </div>
          <div className="feature-card">
            <div className="icon">💼</div>
            <h3>Find Skilled Talent</h3>
            <p>Browse through profiles of verified freelancers across all domains.</p>
          </div>
          <div className="feature-card">
            <div className="icon">🔒</div>
            <h3>Secure Payments</h3>
            <p>Work with confidence knowing your payments and data are secure.</p>
          </div>
          <div className="feature-card">
            <div className="icon">📊</div>
            <h3>Track Progress</h3>
            <p>Monitor project status and proposals through an intuitive dashboard.</p>
          </div>
        </div>
      </section>

      {/* FOOTER */}
      <footer className="footer">
        <p>© 2025 FreelanceHub. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default LandingPage;
